#include <bits/stdc++.h>
using namespace std;

int n,m;
long long f[18][18][1<<17],g[1<<17];
bool b[20][20];
vector<int> e[20];

void dfs(int x,int fa){
    for(int i=1;i<=n;i++)
        for(int j=1;j<1<<n;j++)
            if((j>>i-1)&1)
                f[x][i][j]=1;
    for(int y:e[x])
        if(y!=fa){
            dfs(y,x);
            for(int i=1;i<=n;i++)
                for(int k=1;k<1<<n;k++){
                    long long sum=0;
                    for(int j=1;j<=n;j++)
                        if(b[i][j])
                            sum+=f[y][j][k];
                    f[x][i][k]*=sum;
                }
        }
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1,u,v;i<=m;i++){
        scanf("%d%d",&u,&v);
        b[u][v]=b[v][u]=1;
    }
    for(int i=1,u,v;i<n;i++){
        scanf("%d%d",&u,&v);
        e[u].push_back(v);
        e[v].push_back(u);
    }
    dfs(1,0);
    for(int i=0;i<1<<17;i++)
        for(int j=1;j<=n;j++)
            g[i]+=f[1][j][i];
    for(int i=0;i<n;i++)
        for(int j=1;j<1<<n;j++)
            if((j>>i)&1)
                g[j]-=g[j-(1<<i)];
    printf("%lld",g[(1<<n)-1]);
    return 0;
}
